VALUES
  ('heelevel3-5ff21eeb-moex-00224', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '根據稅捐稽徵法之規定，下列各項繳納稅捐文書之送達中，何者並非合法？', '["應受送達之納稅義務人正在服兵役，稅捐文書向其配偶送達", "納稅義務人為土地之全體公同共有人，稅捐繳款書僅向其中一人為送達", "納稅義務人為土地之全體公同共有人者，一律以公告方式送達於全體公同共有人", "以房東作為納稅義務人之房屋稅，因該房屋正在租賃關係存續中，房屋稅之稅單送達於房 屋之使用人即房客"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00225', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '稅捐稽徵機關對於課稅基礎，經調查仍不能確定或調查費用過鉅時，或納稅義務人未履行稅 捐稽徵之協力義務者，機關得進行推計。關於推計之說明，下列何者正確？', '["推計所確定之應稅事實，為真正之事實", "推計之結果，應當盡可能接近實質之真實", "推計之結果，得以作為納稅義務人依所漏稅額裁罰之計算基礎", "推計之進行，均應當報請上級稅捐稽徵機關核准"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00226', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '納稅者基於獲得租稅利益，違背稅法之立法目的，濫用法律形式，以非常規交易規避租稅構 成要件之該當，以達成與交易常規相當之經濟效果，為租稅規避。關於租稅規避之說明，下 列何者正確？', '["租稅規避為違法行為", "租稅規避所造成者，為租稅逃漏之結果", "納稅義務人所進行之申報構成租稅規避者，倘若並無對重要事項隱匿或為虛偽不實陳述或 提供不正確資料，致使稅捐稽徵機關短漏核定稅捐者，稅捐稽徵機關原則上僅得予以調整、 不得處罰", "針對租稅規避事項，納稅者得在從事特定交易行為前，提供相關證明文件，向稅捐稽徵機 關申請諮詢，稅捐稽徵機關應於三個月內答覆"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00227', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '關於稅務訴訟之訴訟標的，傳統學理上有所謂「總額主義」與「爭點主義」之區別。我國納 稅者權利保護法第21條第1項前段規定：「納稅者不服課稅處分，經復查決定後提起行政爭 訟，於訴願審議委員會決議前或行政訴訟事實審言詞辯論終結前，得追加或變更主張課稅處 分違法事由，受理訴願機關或行政法院應予審酌」。在解釋上：', '["較為接近「爭點主義」", "較為接近「總額主義」", "在申報稅之案件中較接近「爭點主義」、在底冊稅之案件中較接近「總額主義」", "已經揚棄了「總額主義」與「爭點主義」之區分，改採「職權探知主義」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00228', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '稅捐核課期間之起算，依法應由納稅義務人申報繳納之稅捐，已在規定期間內申報者，自申 報日起算。但是倘若應納稅捐為印花稅，其起算期間之基準日為：', '["應稅交易完成年度之12月31日起算", "自應貼用印花稅票交易雙方意思表示合致日起算", "自機關依法發動調查日起算", "自依法應貼用印花稅票日起算"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00229', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '關於稅捐稽徵法之核課期間規定，依110年12月17日修正公布之條文，下列何者為此次修 正所確定的內容？', '["確定核課期間為除斥期間之性質", "確定核課期間不必有法律明文規定", "確定核課期間為消滅時效之性質", "確定核課期間不得因任何理由延長"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00230', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '下列所得稅之扣除額，何者並非基於量能課稅原則？', '["醫藥及生育費", "薪資所得特別扣除", "財產交易損失", "納稅義務人對於教育、文化、公益、慈善機構或團體之捐贈"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00231', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '司法院釋字第 745 號解釋理由書表示：「所得課稅應以收入減除成本及必要費用後的客觀淨 值，而非所得毛額，作為稅基。」試問，該論述係涉及下列何者原則？', '["量能課稅原則", "實質課稅原則", "信賴保護原則", "租稅法律原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00232', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '下列何者並非納稅義務人違反協力義務之法律效果？', '["課處行為罰", "推計課稅", "稽徵機關證明程度之減輕", "課處漏稅罰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00233', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '熱門甲服飾店經人檢舉未開立發票，主管稅捐稽徵機關指定稽徵人員乙依法對甲服飾店進行 調查。下列敘述何者正確？', '["乙為調查甲服飾店之營業所得，基於納稅義務人對於課稅事項負有主觀之舉證責任，乙可 要求甲服飾店提示帳簿", "乙因甲服飾店多次未提出帳簿，在調查仍不能確定課稅基礎後，得依同業利潤標準推計甲 之營業所得", "乙因甲服飾店多次未提出帳簿，欲依推計課稅核課甲之營業所得，倘若有兩種推計之方法， 乙可依其行政裁量權選擇其中一種方法", "乙依同業利潤標準推計甲之營業所得，並可依此作為處以漏稅罰之基礎"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL)
